  } else {
    LeftmostEmptyNone(rooms[1..]);
  }
}

lemma RightmostEmptyIs(rooms: seq<int>, i: int)
  requires 0 <= i < |rooms|
  requires rooms[i] == 0
  requires forall j :: i < j < |rooms| ==> rooms[j] != 0
  ensures RightmostEmpty(rooms) == i
  decreases |rooms|
{
