  } else {
    RightmostEmptyIs(rooms[..|rooms| - 1], i);
  }
}

lemma RightmostEmptyNone(rooms: seq<int>)
  requires forall j :: 0 <= j < |rooms| ==> rooms[j] != 0
  ensures RightmostEmpty(rooms) == -1
  decreases |rooms|
{
  if |rooms| == 0 {
  } else {
    RightmostEmptyNone(rooms[..|rooms| - 1]);
  }
}

