        invariant !found ==> rooms == old_rooms
        invariant !found ==> forall j :: 0 <= j < i ==> old_rooms[j] != 0
        invariant found ==> rooms == HotelAfterEvent(old_rooms, 'L')
        decreases !found, 10 - i
      {
        if rooms[i] == 0 {
