      }
    } else if ch == 'R' {
      var i := 9;
      var found := false;
      while i >= 0 && !found
        invariant -1 <= i <= 9
        invariant |rooms| == 10
        invariant !found ==> rooms == old_rooms
        invariant !found ==> forall j :: i < j < 10 ==> old_rooms[j] != 0
        invariant found ==> rooms == HotelAfterEvent(old_rooms, 'R')
        decreases !found, i + 1
      {
        if rooms[i] == 0 {
          RightmostEmptyIs(old_rooms, i);
          rooms := rooms[i := 1];
          found := true;
        } else {
          i := i - 1;
        }
      }
      if !found {
        RightmostEmptyNone(old_rooms);
      }
    } else if '0' <= ch <= '9' {
      var i := (ch as int) - ('0' as int);
      rooms := rooms[i := 0];
    }
    assert rooms == HotelAfterEvent(old_rooms, ch);
    assert rooms == HotelAfterEvents(events[..idx]);
    idx := idx + 1;
  }
  assert rooms == HotelAfterEvents(events);
